import React from 'react';

export default function BookSearch({ filters, setFilters, onSearch }) {
  return (
    <form className="flex flex-col md:flex-row gap-4 mb-6" role="search" aria-label="Book search form" onSubmit={e => { e.preventDefault(); onSearch(); }}>
      <label className="flex-1" htmlFor="search-title">
        <span className="block text-sm font-medium mb-1">Title</span>
        <input id="search-title" name="title" type="text" className="w-full p-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-600" value={filters.title} onChange={e => setFilters(f => ({ ...f, title: e.target.value }))} aria-label="Search by title" />
      </label>
      <label className="flex-1" htmlFor="search-author">
        <span className="block text-sm font-medium mb-1">Author</span>
        <input id="search-author" name="author" type="text" className="w-full p-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-600" value={filters.author} onChange={e => setFilters(f => ({ ...f, author: e.target.value }))} aria-label="Search by author" />
      </label>
      <label className="flex-1" htmlFor="search-aisle">
        <span className="block text-sm font-medium mb-1">Aisle</span>
        <input id="search-aisle" name="aisle" type="text" className="w-full p-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-600" value={filters.aisle} onChange={e => setFilters(f => ({ ...f, aisle: e.target.value }))} aria-label="Search by aisle" />
      </label>
      <button type="submit" className="px-6 py-2 bg-blue-700 text-white rounded-lg font-semibold focus:outline-none focus:ring-2 focus:ring-blue-600 mt-6 md:mt-0" aria-label="Search books">Search</button>
    </form>
  );
}
