import React from 'react';

export default function BookCard({ book }) {
  return (
    <article className="bg-white rounded-lg shadow-md p-6 mb-4 border border-gray-200" tabIndex={0} aria-label={`Book: ${book.title}`}>
      <header className="flex items-center justify-between mb-2">
        <h2 className="text-xl font-bold" id={`book-title-${book.id}`}>{book.title}</h2>
        <span className={`px-2 py-1 rounded text-xs font-semibold ${book.quantity > 0 ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}
          role="status" aria-live="polite">
          {book.quantity > 0 ? 'Available' : 'Unavailable'}
        </span>
      </header>
      <div className="mb-2">
        <span className="block text-gray-700"><strong>Author:</strong> {book.author}</span>
        <span className="block text-gray-700"><strong>Category:</strong> {book.category}</span>
        <span className="block text-gray-700"><strong>ISBN:</strong> {book.isbn}</span>
        <span className="block text-gray-700"><strong>Aisle:</strong> {book.aisle}</span>
        <span className="block text-gray-700"><strong>Shelf:</strong> {book.shelf}</span>
        <span className="block text-gray-700"><strong>Quantity:</strong> {book.quantity}</span>
      </div>
    </article>
  );
}
